      anchor,
      { width: rect.width, height: rect.height },
      getViewportSize(),
    );
    menu.style.left = placement.left + 'px';
    menu.style.top = placement.top + 'px';
    btn?.setAttribute('aria-expanded', 'true');
    // aria-haspopup="menu" contract: move focus INTO the menu, onto its first
    // item. Use items[0] (the insertion-order first child) rather than a
    // comma selector like querySelector('button, a'): some DOM test hosts
    // evaluate comma selectors in selector-list order instead of document
    // order, which would focus a later <button> instead of a leading <a>.
